-- SIS v.2.0 - DEIVID, S.A.


Drop Procedure ap_banisi3;

Create Procedure "informix".ap_banisi3()
Returning	smallint,-- motivo de rechazo
		   	varchar(100); --cod_cliente	

			
Define _renglon			smallint;
Define _no_poliza		char(10);
Define _secuencia_email	integer;
Define _secuencia		integer;
Define _cod_cliente		char(10);
Define _email			char(100);
Define _existe			smallint;
Define _habilitar		smallint;
Define _mail_err		smallint;
Define _error_cod, _error_isam integer;
Define _error_desc		varchar(100);

SET ISOLATION TO DIRTY READ;

--set debug file to "sp_cob264.trc";
--trace on;
begin
on exception set _error_cod, _error_isam, _error_desc
	return _error_cod, _no_poliza || " - " || trim(_error_desc);
end exception

